function solve(n) {
    function convertToBase(num, base) {
        if (num === 0) return "0";
        let result = '';
        while (num > 0) {
            let digit = num % base;
            let c;
            if (digit < 10) {
                c = String.fromCharCode('0'.charCodeAt(0) + digit);
            } else {
                c = String.fromCharCode('A'.charCodeAt(0) + (digit - 10));
            }
            result = c + result;
            num = Math.floor(num / base);
        }
        return result;
    }

    let n2 = n * n;
    let n3 = n2 * n;

    let hexPart = convertToBase(n2, 16);
    let base36Part = convertToBase(n3, 36);

    return hexPart + base36Part;
}
```

